import React from "react";

import StarRatings from 'react-star-ratings';
import {Button} from '../commons/Form';


export default class extends React.PureComponent {
  state={
    submitted:false
  }
  constructor(props){
    super(props);
    this.handleRating=this.handleRating.bind(this);
    this.handleChange=this.handleChange.bind(this);
  }
  handleSubmit = (event) => {
    event.preventDefault();

    
    
    typeof window !== "undefined" &&window.fetch("https://usebasin.com/f/71436ab3ce6c.json", {
      method: "POST",
      body: JSON.stringify(this.state),
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
      },
    }).then(()=>{
      this.setState({submitted:true})
    });
  };
  handleChange(event){
      this.setState({[event.target.name]:event.target.value});
  }
  handleRating(item,rating){
    this.setState({[item]:rating});
}
  render = () => (
    
      this.state.submitted===false?
      <div style={{padding:20}}>
      <h1>Feedback for Utsav { new Date().getFullYear() }</h1>
      <form
        // acceptCharset="UTF-8"
        // action="https://usebasin.com/f/71436ab3ce6c"
        // enctype="multipart/form-data"
        // method="POST"
        onSubmit={ this.handleSubmit }
        css={{
          display: "flex",
          flexDirection: "column",
        }}
      >

        <div css={{ display: "flex", flexDirection: "column", padding:20}}>
          <label htmlFor="elements">Which elements of Utsav 2019 did you like the most?</label>
          <textarea id="elements" rows="4" name="Liked Elements" onChange={this.handleChange} placeholder="Feedback" required>
          </textarea>
        </div>

        <div css={{ display: "flex", flexDirection: "column", padding:20 }}>
          <label htmlFor="android-app">How useful was Utsav Android App?</label>
          <StarRatings
          rating={this.state.rateApp}
          starRatedColor="gold"
          changeRating={(rating)=>this.handleRating('rateApp',rating)}
          numberOfStars={5}
        />
        </div>

        <div css={{ display: "flex", flexDirection: "column", padding:20 }}>
          <label htmlFor="android-app">How were the quality of events?</label>
          <StarRatings
          rating={this.state.rateEvent}
          starRatedColor="gold"
          changeRating={(rating)=>this.handleRating('rateEvent',rating)}
          numberOfStars={5}
        />        </div>

        <div css={{ display: "flex", flexDirection: "column", padding:20 }}>
          <label htmlFor="android-app">How would you rate the organization of Utsav?</label>
          <StarRatings
          rating={this.state.rateOrg}
          starRatedColor="gold"
          changeRating={(rating)=>this.handleRating('rateOrg',rating)}
          numberOfStars={5}
        />
        </div>

        <div css={{ display: "flex", flexDirection: "column", padding:20 }}>
          <label htmlFor="elements">Is there anything that would have made experience of Utsav better?</label>
          <textarea id="elements" rows="4" name="Liked Elements" onChange={this.handleChange} placeholder="Feedback" required>
          </textarea>
        </div>

        <div css={{ display: "flex", flexDirection: "column",  padding:20}}>
          <label htmlFor="android-app">How likely are you to recommend Utsav to your friends/acquaintances?</label>
          <StarRatings
          rating={this.state.rateRecommend}
          starRatedColor="gold"
          changeRating={(rating)=>this.handleRating('rateRecommend',rating)}
          numberOfStars={5}
        />
        </div>

        <input type="hidden" id="gotcha" name="_gotcha" />

        <Button styles={{padding:40}} type="submit">Submit</Button>
      </form>
    </div>:<div style={{display:"flex",justifyContent:"center",alignItems:"center",height:"100vh"}}>
          <h1>Thank you for your valuable feedback :)</h1>

    </div>
  );
};
